#include <iostream>
using namespace std;

int main() {
    // 不同进制表示同一个数
    int a = 255;      // 十进制
    int b = 0377;     // 八进制
    int c = 0xFF;     // 十六进制
    int d = 0b11111111; // 二进制(C++14及以上)

    cout << "a = " << a << endl;
    cout << "b = " << b << endl;
    cout << "c = " << c << endl;
    cout << "d = " << d << endl;

    return 0;
}

#include <iostream>
#include <string>
using namespace std;

int main() {
    int n;
    cin >> n;
    string s;
    for (int i = 0; i < n; i++) {
        cin >> s;
        char max_char = '0';
        for (char c : s) {
            if (c > max_char) max_char = c;
        }
        // 二进制、八进制、十进制、十六进制
        cout << (max_char <= '1') << " ";
        cout << (max_char <= '7') << " ";
        cout << (max_char <= '9') << " ";
        cout << ((max_char <= '9') || (max_char >= 'A' && max_char <= 'F')) << endl;
    }
    return 0;
}
